-- Migration 035: Add 'social' to terms_versions subscription_type enum
-- and insert initial Social Central terms version

-- 1. Add 'social' to the subscription_type ENUM
ALTER TABLE terms_versions
  MODIFY COLUMN subscription_type ENUM('general','verification','verified','shipping_labels','marketplace','website','websites','sites','wholesale','addons','crm','social') DEFAULT 'general';

-- 2. Also add 'social' to user_terms_acceptance subscription_type ENUM
ALTER TABLE user_terms_acceptance
  MODIFY COLUMN subscription_type ENUM('general','verification','verified','shipping_labels','marketplace','website','websites','sites','wholesale','addons','crm','social') DEFAULT 'general';

